#!/usr/bin/env node
// Build src/suno-production/knowledge-bundle.ts from src/suno-production/knowledge/*.md.
//
// Usage:
//   node scripts/build-knowledge-bundle.mjs --check   (default; CI: fail if out of sync)
//   node scripts/build-knowledge-bundle.mjs --write   (regenerate file)
//
// The bundle ships every sunomanual knowledge file as inline TypeScript string
// constants so prompt builders no longer rely on fileURLToPath()/readFile() at
// runtime. Distribution-safe (no path lookup in tarball install).

import { readFile, writeFile } from "node:fs/promises";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const SCRIPT_DIR = dirname(fileURLToPath(import.meta.url));
const KNOWLEDGE_DIR = join(SCRIPT_DIR, "..", "src", "suno-production", "knowledge");
const BUNDLE_PATH = join(SCRIPT_DIR, "..", "src", "suno-production", "knowledge-bundle.ts");

const KNOWLEDGE_FILES = [
  "README.md",
  "english_lyrics.md",
  "lyric_craft.md",
  "master_reference.md",
  "rap_and_flow.md",
  "song_structures.md",
  "style_catalog.md",
  "suno_v55_reference.md",
  "yaml_template.md"
];

function escapeForBacktick(text) {
  return text
    .replace(/\\/g, "\\\\")
    .replace(/`/g, "\\`")
    .replace(/\$\{/g, "\\${");
}

async function generateBundle() {
  const entries = [];
  for (const filename of KNOWLEDGE_FILES) {
    const content = await readFile(join(KNOWLEDGE_DIR, filename), "utf8");
    entries.push({ filename, content });
  }

  const lines = [
    "// AUTO-GENERATED by scripts/build-knowledge-bundle.mjs — do not edit by hand.",
    "// Regenerate with: node scripts/build-knowledge-bundle.mjs --write",
    "//",
    "// Source: sunomanual (MIT, Copyright 2025-2026 usedhonda)",
    "",
    "export const KNOWLEDGE_FILES = [",
    ...entries.map(({ filename }) => `  ${JSON.stringify(filename)},`),
    "] as const;",
    "",
    "export type KnowledgeFile = (typeof KNOWLEDGE_FILES)[number];",
    "",
    "export const KNOWLEDGE_BUNDLE: Record<KnowledgeFile, string> = {"
  ];

  for (const { filename, content } of entries) {
    lines.push(`  ${JSON.stringify(filename)}: \`${escapeForBacktick(content)}\`,`);
  }
  lines.push("};");
  lines.push("");

  return lines.join("\n");
}

async function main() {
  const args = process.argv.slice(2);
  const writeMode = args.includes("--write");
  const verbose = args.includes("--verbose");

  const generated = await generateBundle();

  if (writeMode) {
    await writeFile(BUNDLE_PATH, generated, "utf8");
    if (verbose) {
      console.log(`Wrote ${BUNDLE_PATH} (${generated.length} chars)`);
    } else {
      console.log(`Wrote ${BUNDLE_PATH}`);
    }
    return;
  }

  // Default: --check mode (used by CI / build:knowledge).
  const existing = await readFile(BUNDLE_PATH, "utf8").catch(() => "");
  if (existing !== generated) {
    console.error("knowledge-bundle.ts is out of sync with src/suno-production/knowledge/*.md.");
    console.error("Run: node scripts/build-knowledge-bundle.mjs --write");
    process.exit(1);
  }
  if (verbose) {
    console.log(`knowledge-bundle.ts is in sync (${generated.length} chars, ${KNOWLEDGE_FILES.length} files).`);
  }
}

main().catch((error) => {
  console.error(error);
  process.exit(1);
});
